    const num = Number(trimmed);
    return num;
  }

  return value;
}

// ---------------------------------------------------------------------------
// Low-level line parser – handles quoting / escaping for a single record
// ---------------------------------------------------------------------------

function parseFields(
  line: string,
  delimiter: string,
  quote: string
): string[] {
  const fields: string[] = [];
  let current = "";
  let inQuotes = false;
  let i = 0;

  while (i < line.length) {
    const ch = line[i];

    if (inQuotes) {
      if (ch === quote) {
        // Look ahead – escaped quote?
        if (i + 1 < line.length && line[i + 1] === quote) {
          current += quote;
          i += 2;
          continue;
        }
        // End of quoted section
        inQuotes = false;
        i++;
        continue;
      }
      current += ch;
      i++;
    } else {
      if (ch === quote) {
        inQuotes = true;
        i++;
        continue;
      }
      // Check for multi-char delimiter
      if (line.substring(i, i + delimiter.length) === delimiter) {
        fields.push(current);
