        inQuotes = true;
        current += ch;
        i++;
        continue;
      }
      if (input.substring(i, i + lineSeparator.length) === lineSeparator) {
        lines.push(current);
        current = "";
        i += lineSeparator.length;
        continue;
      }
      current += ch;
      i++;
    }
  }

  // Remaining content is the last line
  if (current.length > 0) {
    lines.push(current);
  }

  return lines;
}

// ---------------------------------------------------------------------------
// Main entry point
// ---------------------------------------------------------------------------

export function parseCSV(input: string, options?: CSVOptions): CSVResult {
  const delimiter = options?.delimiter ?? ",";
  const quote = options?.quote ?? '"';
  const lineSeparator = options?.lineSeparator ?? "\n";

  const errors: CSVError[] = [];

  // Handle empty / whitespace-only input
  const trimmed = input.trim();
  if (trimmed === "") {
    return buildResult([], [], errors);
  }

  const lines = splitLogicalLines(trimmed, lineSeparator, quote);

  if (lines.length === 0) {
    return buildResult([], [], errors);
  }

  // First line → headers
  const headers = parseFields(lines[0], delimiter, quote).map((h) => h.trim());

  const rows: Record<string, unknown>[] = [];

  for (let i = 1; i < lines.length; i++) {
    const line = lines[i];

    // Skip completely empty lines
    if (line.trim() === "") continue;

    const fields = parseFields(line, delimiter, quote);

    if (fields.length !== headers.length) {
      errors.push({
        row: i + 1, // 1-based, header is row 1
        message: `Expected ${headers.length} fields but got ${fields.length}`,
      });
      continue; // skip malformed row
    }

    const row: Record<string, unknown> = {};
    for (let j = 0; j < headers.length; j++) {
      row[headers[j]] = coerce(fields[j]);
    }
    rows.push(row);
  }

  return buildResult(rows, headers, errors);
}

// ---------------------------------------------------------------------------
// Build the result object with its helper methods
// ---------------------------------------------------------------------------

function buildResult(
  rows: Record<string, unknown>[],
  headers: string[],
  errors: CSVError[]
): CSVResult {
  return {
    rows,
    headers,
    errors,

    filter(predicate: (row: Record<string, unknown>) => boolean) {
      return rows.filter(predicate);
    },

    sum(column: string): number {
      let total = 0;
      for (const row of rows) {
        const v = row[column];
        if (typeof v === "number") total += v;
      }
      return total;
    },

    average(column: string): number {
      let total = 0;
      let count = 0;
      for (const row of rows) {
        const v = row[column];
        if (typeof v === "number") {
          total += v;
          count++;
        }
      }
      return count === 0 ? 0 : total / count;
    },

    count(): number {
      return rows.length;
    },

    groupBy(column: string): Map<unknown, Record<string, unknown>[]> {
      const map = new Map<unknown, Record<string, unknown>[]>();
      for (const row of rows) {
        const key = row[column];
        if (!map.has(key)) map.set(key, []);
        map.get(key)!.push(row);
      }
      return map;
    },
  };
}

