// csv-parser.ts — A full-featured CSV parser library

export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: Record<string, unknown>[];
  headers: string[];
  errors: CSVError[];
  filter: (predicate: (row: Record<string, unknown>) => boolean) => Record<string, unknown>[];
  sum: (column: string) => number;
  average: (column: string) => number;
  count: () => number;
  groupBy: (column: string) => Map<unknown, Record<string, unknown>[]>;
}

// ---------------------------------------------------------------------------
// Field-level type coercion
// ---------------------------------------------------------------------------

function coerce(value: string): unknown {
  // Empty string → null
  if (value === "") return null;

  // Explicit null literals
  if (value === "null" || value === "NULL") return null;

  // Booleans (case-insensitive)
  if (value.toLowerCase() === "true") return true;
  if (value.toLowerCase() === "false") return false;

  // Numbers – integers and floats.  We reject strings that are only
  // whitespace, or that would coerce oddly (e.g. "0x10", "Infinity").
  const trimmed = value.trim();
  if (trimmed !== "" && !isNaN(Number(trimmed)) && isFinite(Number(trimmed))) {
    const num = Number(trimmed);
    return num;
  }

  return value;
}

// ---------------------------------------------------------------------------
// Low-level line parser – handles quoting / escaping for a single record
// ---------------------------------------------------------------------------

function parseFields(
  line: string,
  delimiter: string,
  quote: string
): string[] {
  const fields: string[] = [];
  let current = "";
  let inQuotes = false;
  let i = 0;

  while (i < line.length) {
    const ch = line[i];

    if (inQuotes) {
      if (ch === quote) {
        // Look ahead – escaped quote?
        if (i + 1 < line.length && line[i + 1] === quote) {
          current += quote;
          i += 2;
          continue;
        }
        // End of quoted section
        inQuotes = false;
        i++;
        continue;
      }
      current += ch;
      i++;
    } else {
      if (ch === quote) {
        inQuotes = true;
        i++;
        continue;
      }
      // Check for multi-char delimiter
      if (line.substring(i, i + delimiter.length) === delimiter) {
        fields.push(current);
        current = "";
        i += delimiter.length;
        continue;
      }
      current += ch;
      i++;
    }
  }

  // Push the last field
  fields.push(current);

  return fields;
}

// ---------------------------------------------------------------------------
// Split input into logical lines, respecting quoted fields that span lines
// ---------------------------------------------------------------------------

function splitLogicalLines(
  input: string,
  lineSeparator: string,
  quote: string
): string[] {
  const lines: string[] = [];
  let current = "";
  let inQuotes = false;
  let i = 0;

  while (i < input.length) {
    const ch = input[i];

    if (inQuotes) {
      if (ch === quote) {
        if (i + 1 < input.length && input[i + 1] === quote) {
          current += quote + quote;
          i += 2;
          continue;
        }
        inQuotes = false;
        current += ch;
        i++;
        continue;
      }
      current += ch;
      i++;
    } else {
      if (ch === quote) {
        inQuotes = true;
        current += ch;
        i++;
        continue;
      }
      if (input.substring(i, i + lineSeparator.length) === lineSeparator) {
        lines.push(current);
        current = "";
        i += lineSeparator.length;
        continue;
      }
      current += ch;
      i++;
    }
  }

  // Remaining content is the last line
  if (current.length > 0) {
    lines.push(current);
  }

  return lines;
}

// ---------------------------------------------------------------------------
// Main entry point
// ---------------------------------------------------------------------------

export function parseCSV(input: string, options?: CSVOptions): CSVResult {
  const delimiter = options?.delimiter ?? ",";
  const quote = options?.quote ?? '"';
  const lineSeparator = options?.lineSeparator ?? "\n";

  const errors: CSVError[] = [];

  // Handle empty / whitespace-only input
  const trimmed = input.trim();
  if (trimmed === "") {
    return buildResult([], [], errors);
  }

  const lines = splitLogicalLines(trimmed, lineSeparator, quote);

  if (lines.length === 0) {
    return buildResult([], [], errors);
  }

  // First line → headers
  const headers = parseFields(lines[0], delimiter, quote).map((h) => h.trim());

  const rows: Record<string, unknown>[] = [];

  for (let i = 1; i < lines.length; i++) {
    const line = lines[i];

    // Skip completely empty lines
    if (line.trim() === "") continue;

    const fields = parseFields(line, delimiter, quote);

    if (fields.length !== headers.length) {
      errors.push({
        row: i + 1, // 1-based, header is row 1
        message: `Expected ${headers.length} fields but got ${fields.length}`,
      });
      continue; // skip malformed row
    }

    const row: Record<string, unknown> = {};
    for (let j = 0; j < headers.length; j++) {
      row[headers[j]] = coerce(fields[j]);
    }
    rows.push(row);
  }

  return buildResult(rows, headers, errors);
}

// ---------------------------------------------------------------------------
// Build the result object with its helper methods
// ---------------------------------------------------------------------------

function buildResult(
  rows: Record<string, unknown>[],
  headers: string[],
  errors: CSVError[]
): CSVResult {
  return {
    rows,
    headers,
    errors,

    filter(predicate: (row: Record<string, unknown>) => boolean) {
      return rows.filter(predicate);
    },

    sum(column: string): number {
      let total = 0;
      for (const row of rows) {
        const v = row[column];
        if (typeof v === "number") total += v;
      }
      return total;
    },

    average(column: string): number {
      let total = 0;
      let count = 0;
      for (const row of rows) {
        const v = row[column];
        if (typeof v === "number") {
          total += v;
          count++;
        }
      }
      return count === 0 ? 0 : total / count;
    },

    count(): number {
      return rows.length;
    },

    groupBy(column: string): Map<unknown, Record<string, unknown>[]> {
      const map = new Map<unknown, Record<string, unknown>[]>();
      for (const row of rows) {
        const key = row[column];
        if (!map.has(key)) map.set(key, []);
        map.get(key)!.push(row);
      }
      return map;
    },
  };
}
